VALUES ('New Again Houses', 'nah', 'scale', 'active', 999, 'ghl', 'true', 'true');

-- Get the tenant ID
SET @nahTenantId = LAST_INSERT_ID();

-- Seed subscription plans
INSERT INTO `subscription_plans` (`name`, `code`, `description`, `priceMonthly`, `priceYearly`, `maxUsers`, `maxCrmIntegrations`, `features`, `sortOrder`)
VALUES 
  ('Starter', 'starter', 'Perfect for small teams getting started with AI call coaching', 9900, 99000, 3, 1, '["call_grading", "basic_analytics", "team_dashboard"]', 1),
  ('Growth', 'growth', 'For growing teams that need more users and advanced features', 24900, 249000, 10, 2, '["call_grading", "advanced_analytics", "team_dashboard", "custom_rubrics", "training_materials"]', 2),
  ('Scale', 'scale', 'Enterprise-grade features for large organizations', 49900, 499000, 999, 5, '["call_grading", "advanced_analytics", "team_dashboard", "custom_rubrics", "training_materials", "api_access", "priority_support", "custom_branding"]', 3);

-- Update existing users to belong to NAH tenant
UPDATE `users` SET `tenantId` = @nahTenantId WHERE `tenantId` IS NULL;

-- Update existing team_members to belong to NAH tenant
UPDATE `team_members` SET `tenantId` = @nahTenantId WHERE `tenantId` IS NULL;

-- Update existing calls to belong to NAH tenant
UPDATE `calls` SET `tenantId` = @nahTenantId WHERE `tenantId` IS NULL;

-- Update existing call_grades to belong to NAH tenant
UPDATE `call_grades` SET `tenantId` = @nahTenantId WHERE `tenantId` IS NULL;

-- Set Corey as super_admin and tenant admin
UPDATE `users` SET `role` = 'super_admin', `isTenantAdmin` = 'true' WHERE `email` = 'corey@newagainhouses.com';

